import React, { useState,useEffect } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

function WeeklyReport(){
     const [nutritions,setNutritions]=useState([]);
        const navigate=useNavigate();

    async function handlePage() {
        try{
            const response=await fetch('http://localhost:5000/weeklyreport');
            const data=await response.json();
            console.log(data);
            setNutritions(data);
        }
        catch(err){
            console.log(err.message);
        }
    }

    function goToDashboard(){
        navigate('/dashboard');
    }

    useEffect(()=>{handlePage()},[]);

    return(
        <>
            <div>
                {nutritions.map((item,index)=>
                    <h2 key={index}>Date:{item.day} {"  |  "}  Carbs:{item.total_carbs} {"  |  "} Calories:{item.total_calories}</h2>
                )}
            </div>
           
           <table>
                <tr>
                    <th>Date</th>
                    <th>Carbs</th>
                    <th>Calories</th>
                </tr>
                {nutritions.map((item,index)=>
                    <tr key={index}>
                        <td>{item.day}</td>
                        <td>{item.total_carbs}</td>
                        <td>{item.total_calories}</td>
                    </tr>
                )}
           </table>
            
            
        </>
    );
}

export default WeeklyReport;
